import html
import json
import sys
import traceback
from typing import Any

from ledger.chain import load_ledger
from ledger.verify import verify_chain

_DEFAULT_LEDGER_PATH: str = "ledger/bench-ledger.json"
_HASH_SHORT_LEN: int = 12


def generate_viewer_html(ledger_path: str = _DEFAULT_LEDGER_PATH) -> str:
    """Return a complete self-contained HTML string rendering the ledger.

    On any unexpected error, logs to stderr with a full traceback and
    returns a minimal error HTML page â€” never raises.
    """
    try:
        entries: list[dict] = load_ledger(ledger_path)
        chain_status: dict = _compute_chain_status(ledger_path)
        stats: dict = _compute_stats(entries)
        return _build_html(stats, chain_status, entries)
    except Exception as e:
        print(
            f"[bench viewer] generate_viewer_html failed: "
            f"{type(e).__name__}: {e}",
            file=sys.stderr,
        )
        traceback.print_exc(file=sys.stderr)
        return _build_error_html(f"{type(e).__name__}: {e}")


def _compute_chain_status(ledger_path: str) -> dict:
    """Distill ``verify_chain`` output into a viewer-friendly status dict."""
    result: dict = verify_chain(ledger_path)

    if result.get("valid"):
        if int(result.get("entries", 0)) == 0:
            return {
                "status": "EMPTY",
                "failure_index": None,
                "message": "No entries yet.",
            }
        return {
            "status": "VALID",
            "failure_index": None,
            "message": "Chain intact.",
        }

    failure_index: Any = result.get("failure_index")
    try:
        idx: int | None = (
            int(failure_index) if failure_index is not None else None
        )
    except (TypeError, ValueError):
        idx = None

    return {
        "status": "BROKEN",
        "failure_index": idx,
        "message": str(result.get("message", "Chain broken.")),
    }


def _compute_stats(entries: list[dict]) -> dict:
    """Replicate ``cmd_stats`` logic so the banner matches terminal output."""
    total: int = len(entries)
    passed: int = 0
    vetoed: int = 0
    pipeline_errors: int = 0
    citation_counts: dict[str, int] = {}

    for entry in entries:
        oracle: Any = entry.get("oracle")
        oracle_dict: dict = oracle if isinstance(oracle, dict) else {}
        verdict: Any = oracle_dict.get("verdict")

        if _entry_has_pipeline_error(entry):
            pipeline_errors += 1

        if verdict == "PASS":
            passed += 1
        elif verdict == "VETO":
            vetoed += 1
            citations: Any = oracle_dict.get("constraint_citations")
            if isinstance(citations, list):
                for cid in citations:
                    if isinstance(cid, str):
                        citation_counts[cid] = citation_counts.get(cid, 0) + 1
                    elif isinstance(cid, dict):
                        raw = cid.get("constraint_id")
                        if isinstance(raw, str):
                            citation_counts[raw] = citation_counts.get(raw, 0) + 1
                    else:
                        print(
                            f"[bench viewer] unexpected citation type: {type(cid).__name__}",
                            file=sys.stderr,
                        )

    most_cited: tuple[str, int] | None = None
    if citation_counts:
        most_cited = max(citation_counts.items(), key=lambda kv: kv[1])

    return {
        "total": total,
        "passed": passed,
        "vetoed": vetoed,
        "pipeline_errors": pipeline_errors,
        "most_cited": most_cited,
    }


def _entry_has_pipeline_error(entry: dict) -> bool:
    for stage in ("challenger", "defender", "oracle"):
        stage_result: Any = entry.get(stage)
        if (
            isinstance(stage_result, dict)
            and stage_result.get("status") == "PIPELINE_ERROR"
        ):
            return True
    return False


def _pct(part: int, total: int) -> str:
    if total <= 0:
        return "0.0%"
    return f"{part / total * 100:.1f}%"


def _build_html(
    stats: dict,
    chain_status: dict,
    entries: list[dict],
) -> str:
    """Assemble the full HTML document as a single string."""
    entries_json: str = json.dumps(entries, default=str).replace("</", "<\\/")
    chain_json: str = json.dumps(chain_status).replace("</", "<\\/")

    total: int = int(stats.get("total", 0))
    passed: int = int(stats.get("passed", 0))
    vetoed: int = int(stats.get("vetoed", 0))
    passed_pct: str = _pct(passed, total)
    vetoed_pct: str = _pct(vetoed, total)

